        if symbols is not None:
            symbolsLength = len(symbols)
        request: dict = {}
        if symbolsLength == 1:
            market = self.get_market_from_symbols(symbols)
            request['symbol'] = market['id']
        response = self.contractGetCapiV3MarketPremiumIndex(self.extend(request, params))
        #
