            if limit is not None:
                request['limit'] = limit
            request, params = self.handle_until_option('endTime', request, params)
            trigger = self.safe_bool(params, 'trigger', False)
            if trigger:
                params = self.omit(params, 'trigger')
                #
                #     [
                #         {
