        #         "size": "100",
        #         "openValue": "9.31100",
        #         "openFee": "0.00744880",
        #         "fundingFee": "0",
        #         "isolatedMargin": "0",
        #         "autoAppendIsolatedMargin": False,
        #         "cumOpenSize": "100",
        #         "cumOpenValue": "9.31100",
        #         "cumOpenFee": "0.00744880",
        #         "cumCloseSize": "0",
        #         "cumCloseValue": "0",
        #         "cumCloseFee": "0",
        #         "cumFundingFee": "0",
        #         "cumLiquidateFee": "0",
